import app from 'flarum/forum/app';
import Page from 'flarum/common/components/Page';
import PageStructure from 'flarum/forum/components/PageStructure';
import IndexSidebar from 'flarum/forum/components/IndexSidebar';
import LoadingIndicator from 'flarum/common/components/LoadingIndicator';
import PicksState from './picks/PicksState';
import MatchesTab from './picks/MatchesTab';
import MyPicksTab from './picks/MyPicksTab';
import LeaderboardTab from './picks/LeaderboardTab';
import HistoryTab from './picks/HistoryTab';

/**
 * Thin orchestrator for the /picks page. All state + data loading lives in
 * PicksState; each tab is its own presentational component reading from that
 * shared state. This component only owns the tab bar and active-tab dispatch.
 */
export default class PicksPage extends Page {
  picksState = (() => new PicksState())();
  oninit(vnode) {
    super.oninit(vnode);
    app.setTitle(String(app.forum.attribute('picksNavLabel') || app.translator.trans('ernestdefoe-picks.lib.nav.picks')));
    this.picksState.init(parseInt(String(m.route.param('weekId') ?? ''), 10));
  }
  view() {
    const state = this.picksState;
    const canView = app.forum.attribute('picksCanView') || app.session.user?.isAdmin();
    const tabs = [{
      key: 'matches',
      label: app.translator.trans('ernestdefoe-picks.lib.nav.matches'),
      icon: 'fas fa-football'
    }, {
      key: 'mypicks',
      label: app.translator.trans('ernestdefoe-picks.lib.nav.my_picks'),
      icon: 'fas fa-check-circle'
    }, {
      key: 'leaderboard',
      label: app.translator.trans('ernestdefoe-picks.lib.nav.leaderboard'),
      icon: 'fas fa-trophy'
    }, {
      key: 'history',
      label: app.translator.trans('ernestdefoe-picks.lib.nav.history'),
      icon: 'fas fa-history'
    }];
    return m(PageStructure, {
      className: "PicksPage",
      sidebar: () => m(IndexSidebar, null)
    }, m("div", {
      className: "PicksPage-inner"
    }, m("div", {
      className: "PicksPage-tabs"
    }, tabs.map(tab => m("button", {
      key: tab.key,
      className: `PicksPage-tab ${state.activeTab === tab.key ? 'PicksPage-tab--active' : ''}`,
      onclick: () => {
        state.activeTab = tab.key;
        if (tab.key === 'leaderboard' && state.leaderboard.length === 0) {
          state.loadLeaderboard();
        }
        if (tab.key === 'history') {
          state.loadLeaderboardHistory();
        }
        m.redraw();
      }
    }, m("i", {
      className: tab.icon
    }), " ", tab.label))), !canView ? m("div", {
      className: "PicksEmpty"
    }, app.translator.trans('ernestdefoe-picks.lib.messages.login_required')) : !state.weeksLoaded ? m(LoadingIndicator, null) : state.weeks.length === 0 && state.activeTab !== 'history' ? m("div", {
      className: "PicksEmpty PicksEmpty--noSchedule"
    }, m("i", {
      className: "fas fa-football"
    }), m("p", null, "No schedule has been imported yet."), m("p", null, "Check back soon!")) : m('[', null, state.activeTab === 'matches' && MatchesTab.component({
      state
    }), state.activeTab === 'mypicks' && MyPicksTab.component({
      state
    }), state.activeTab === 'leaderboard' && LeaderboardTab.component({
      state
    }), state.activeTab === 'history' && HistoryTab.component({
      state
    }))));
  }
}
flarum.reg.add('ernestdefoe-picks', 'forum/components/PicksPage', PicksPage);